using Pwiz.Data.Common.Proteome;

#pragma warning disable CA1707 // underscored type names match cpp pwiz (ProteinList_DecoyGenerator etc.)

namespace Pwiz.Analysis.Proteome;

/// <summary>
/// Doubles a <see cref="ProteinList"/> by appending a decoy version of every target.
/// Port of cpp's <c>pwiz::analysis::ProteinList_DecoyGenerator</c>.
/// </summary>
/// <remarks>
/// <para>The first N proteins are the originals; the next N are decoys generated by the
/// supplied <see cref="IDecoyGeneratorPredicate"/> (reversed sequence, shuffled
/// sequence, etc.) with the predicate's prefix prepended to the id.</para>
/// <para><see cref="Find"/> strips the decoy prefix on lookup so callers can pass either
/// the target id or the decoy id and get the correct ordinal in this doubled list.</para>
/// </remarks>
public sealed class ProteinList_DecoyGenerator : ProteinListWrapper
{
    private readonly IDecoyGeneratorPredicate _predicate;

    /// <summary>Creates a doubled list over <paramref name="inner"/> using
    /// <paramref name="predicate"/> for decoy generation.</summary>
    public ProteinList_DecoyGenerator(ProteinList inner, IDecoyGeneratorPredicate predicate)
        : base(inner)
    {
        ArgumentNullException.ThrowIfNull(predicate);
        _predicate = predicate;
    }

    /// <inheritdoc/>
    public override int Count => Inner.Count * 2;

    /// <inheritdoc/>
    public override int Find(string id)
    {
        ArgumentNullException.ThrowIfNull(id);
        string prefix = _predicate.DecoyPrefix;
        if (prefix.Length > 0 && id.StartsWith(prefix, StringComparison.Ordinal))
        {
            string originalId = id[prefix.Length..];
            int originalIndex = Inner.Find(originalId);
            // Inner.Find returns Inner.Count on miss; surface this list's Count as the
            // miss sentinel so callers can do `find(id) == Count` regardless of which
            // half they were looking at. (cpp returns inner.size() here, which doesn't
            // equal this list's size — a minor sentinel inconsistency we fix.)
            return originalIndex == Inner.Count ? Count : originalIndex + Inner.Count;
        }
        int direct = Inner.Find(id);
        return direct == Inner.Count ? Count : direct;
    }

    /// <inheritdoc/>
    public override Protein GetProtein(int index, bool getSequence = true)
    {
        if ((uint)index >= (uint)Count)
            throw new ArgumentOutOfRangeException(nameof(index));

        int innerCount = Inner.Count;
        int originalIndex = index % innerCount;
        var protein = Inner.GetProtein(originalIndex, getSequence);

        // First half is target; second half is generated decoy.
        if (index >= innerCount)
            return _predicate.Generate(protein, index);
        return protein;
    }
}

/// <summary>Decoy-generator hook for <see cref="ProteinList_DecoyGenerator"/>.</summary>
public interface IDecoyGeneratorPredicate
{
    /// <summary>Prefix prepended to a target protein's id to derive the decoy id.</summary>
    string DecoyPrefix { get; }

    /// <summary>Produces a decoy <see cref="Protein"/> from <paramref name="target"/>,
    /// stamping the supplied <paramref name="decoyIndex"/> as its <see cref="Protein.Index"/>.</summary>
    Protein Generate(Protein target, int decoyIndex);
}

/// <summary>Reverses the target's amino-acid sequence. Port of cpp's
/// <c>ProteinList_DecoyGeneratorPredicate_Reversed</c>.</summary>
public sealed class DecoyGeneratorPredicate_Reversed : IDecoyGeneratorPredicate
{
    /// <inheritdoc/>
    public string DecoyPrefix { get; }

    /// <summary>Creates a reversed-decoy predicate with the given id prefix.</summary>
    public DecoyGeneratorPredicate_Reversed(string decoyPrefix)
    {
        ArgumentNullException.ThrowIfNull(decoyPrefix);
        DecoyPrefix = decoyPrefix;
    }

    /// <inheritdoc/>
    public Protein Generate(Protein target, int decoyIndex)
    {
        ArgumentNullException.ThrowIfNull(target);
        // cpp drops the description on decoy generation.
        var seq = target.Sequence;
        var reversed = new char[seq.Length];
        for (int i = 0; i < seq.Length; i++) reversed[seq.Length - 1 - i] = seq[i];
        return new Protein(DecoyPrefix + target.Id, decoyIndex, string.Empty, new string(reversed));
    }
}

/// <summary>Randomly shuffles the target's amino-acid sequence with a seeded RNG.
/// Port of cpp's <c>ProteinList_DecoyGeneratorPredicate_Shuffled</c>.</summary>
/// <remarks>
/// cpp uses <c>std::mt19937</c>; sharp uses <see cref="Random"/> (xoshiro on .NET 6+,
/// not Mersenne Twister). Output sequences will NOT be byte-identical between cpp and
/// sharp, but they're deterministic given the same seed within sharp itself.
/// </remarks>
public sealed class DecoyGeneratorPredicate_Shuffled : IDecoyGeneratorPredicate
{
    private readonly Random _rng;

    /// <inheritdoc/>
    public string DecoyPrefix { get; }

    /// <summary>Creates a shuffled-decoy predicate with the given id prefix and RNG seed.
    /// Pass <c>seed = 0</c> (the cpp default) for the documented "reproducible" mode.</summary>
    public DecoyGeneratorPredicate_Shuffled(string decoyPrefix, int seed = 0)
    {
        ArgumentNullException.ThrowIfNull(decoyPrefix);
        DecoyPrefix = decoyPrefix;
        _rng = new Random(seed);
    }

    /// <inheritdoc/>
    public Protein Generate(Protein target, int decoyIndex)
    {
        ArgumentNullException.ThrowIfNull(target);
        var seq = target.Sequence.ToCharArray();
        // Fisher-Yates over the char array.
        for (int i = seq.Length - 1; i > 0; i--)
        {
            int j = _rng.Next(i + 1);
            (seq[i], seq[j]) = (seq[j], seq[i]);
        }
        return new Protein(DecoyPrefix + target.Id, decoyIndex, string.Empty, new string(seq));
    }
}
